import{_ as a,o as i,c as r,ae as t}from"./chunks/framework.CyZiF_rV.js";const d=JSON.parse('{"title":"KSeF 2.0 - Przewodnik dla Integratorów","description":"","frontmatter":{},"headers":[],"relativePath":"pl/index.md","filePath":"pl/index.md"}'),o={name:"pl/index.md"};function n(l,e,s,k,c,p){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="ksef-2-0-przewodnik-dla-integratorow" tabindex="-1"><strong>KSeF 2.0 - Przewodnik dla Integratorów</strong> <a class="header-anchor" href="#ksef-2-0-przewodnik-dla-integratorow" aria-label="Permalink to &quot;**KSeF 2.0 \\- Przewodnik dla Integratorów**&quot;">​</a></h1><p>22.12.2025</p><p>Niniejszy dokument stanowi kompendium wiedzy dla deweloperów, analityków i integratorów systemów, którzy realizują integrację z Krajowym Systemem e-Faktur (KSeF) w wersji 2.0. Przewodnik koncentruje się na aspektach technicznych i praktycznych związanych z komunikacją z API systemu KSeF.</p><h2 id="wprowadzenie-do-ksef-2-0" tabindex="-1">Wprowadzenie do KSeF 2.0 <a class="header-anchor" href="#wprowadzenie-do-ksef-2-0" aria-label="Permalink to &quot;Wprowadzenie do KSeF 2.0&quot;">​</a></h2><p>Krajowy System e-Faktur (KSeF) to centralny system teleinformatyczny służący do wystawiania i pobierania faktur ustrukturyzowanych w postaci elektronicznej.</p><h2 id="spis-tresci" tabindex="-1">Spis treści <a class="header-anchor" href="#spis-tresci" aria-label="Permalink to &quot;Spis treści&quot;">​</a></h2><p>Przewodnik został podzielony na tematyczne sekcje, odpowiadające kluczowym funkcjom i obszarom integracyjnym w API KSeF:</p><ul><li><a href="./przeglad-kluczowych-zmian-ksef-api-2-0.html">Przegląd kluczowych zmian w KSeF 2.0</a></li><li><a href="./api-changelog.html">Changelog</a></li><li>Uwierzytelnianie <ul><li><a href="./uwierzytelnianie.html">Uzyskiwanie dostępu</a></li><li><a href="./auth/sesje.html">Zarządzanie sesjami</a></li></ul></li><li><a href="./uprawnienia.html">Uprawnienia</a></li><li><a href="./certyfikaty-KSeF.html">Certyfikaty KSeF</a></li><li>Tryby offline <ul><li><a href="./tryby-offline.html">Tryby offline</a></li><li><a href="./offline/korekta-techniczna.html">Korekta techniczna</a></li></ul></li><li><a href="./kody-qr.html">Kody QR</a></li><li><a href="./sesja-interaktywna.html">Sesja interaktywna</a></li><li><a href="./sesja-wsadowa.html">Sesja wsadowa</a></li><li>Pobieranie faktur <ul><li><a href="./pobieranie-faktur/pobieranie-faktur.html">Pobieranie faktur</a></li><li><a href="./pobieranie-faktur/przyrostowe-pobieranie-faktur.html">Przyrostowe pobieranie faktur</a></li></ul></li><li><a href="./tokeny-ksef.html">Zarządzanie tokenami KSeF</a></li><li><a href="./limity/limity.html">Limity</a></li><li><a href="./dane-testowe-scenariusze.html">Dane testowe</a></li></ul><p>Dla każdego obszaru przewidziano:</p><ul><li>szczegółowy opis działania,</li><li>przykład wywołania w językach C# i Java,</li><li>powiązania ze specyfikacją <a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">OpenAPI</a> i kodem biblioteki referencyjnej.</li></ul><p>Przykłady kodu prezentowane w przewodniku zostały przygotowane w oparciu o oficjalne biblioteki open source:</p><ul><li><a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">ksef-client-csharp</a> – biblioteka w języku C#</li><li><a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">ksef-client-java</a> – biblioteka w języku Java</li></ul><p>Obie biblioteki są utrzymywane i rozwijane przez zespoły Ministerstwa Finansów oraz udostępniane publicznie na zasadach open source. Zapewniają pełne wsparcie funkcjonalności API KSeF 2.0, w tym obsługę wszystkich endpointów, modeli danych oraz przykładowych scenariuszy wywołań. Wykorzystanie tych bibliotek pozwala znacząco uprościć proces integracji oraz minimalizuje ryzyko błędnej interpretacji kontraktów API.</p><h2 id="srodowiska-systemu" tabindex="-1">Środowiska Systemu <a class="header-anchor" href="#srodowiska-systemu" aria-label="Permalink to &quot;Środowiska Systemu&quot;">​</a></h2><p>Zestawienie środowisk KSeF API 2.0 zostało opisane w dokumencie <a href="./srodowiska.html">Środowiska KSeF API 2.0</a></p>',15)])])}const h=a(o,[["render",n]]);export{d as __pageData,h as default};
